      pre: [amount > 0usd, status($account) = #active],
      body: validate(amount > 0usd)
        -> check_rules(["R1"])
        -> update($account, {balance: balance($account) + amount})
        -> emit(#Transaction{kind:#deposit, status:#settled}),
      post: balance($result) = balance($account) + amount
    },
    #fn{
      name:"withdraw",
      sig: withdraw(account:@Account, amount:Number) -> #Account | #rejected,
      pre: [amount > 0usd, status($account) = #active],
      body: validate(amount > 0usd)
        -> check_rules(["R1", "R2"])
        -> (balance($account) - amount >= 0usd
            | #rejected{reason:"insufficient-funds"})
        -> update($account, {balance: balance($account) - amount})
        -> emit(#Transaction{kind:#withdrawal, status:#settled}),
      post: balance($result) = balance($account) - amount
        | $result = #rejected
