⟦Γ:Rules⟧{
  ∀t:Task   : t.priority ∈ {1,2,3,4,5}
  ∀t:Task   : t.deadline > now() ∨ t.status ≡ expired

  ∀w:Worker : w.current ≠ ∅ ⇒ w.capacity ≡ 0
  ∀w:Worker : w.current ≡ ∅ ⇒ w.capacity ≥ 1

  ∀t:Task   : t.assignee ≠ ∅ ⇒ t.status ≡ assigned
  ∀t:Task   : t.assignee ≡ ∅ ∧ t.status ≡ assigned ⇒ ⊥

  ∀w:Worker, ∀t1:Task, ∀t2:Task :
    (t1.assignee ≡ w.id ∧ t2.assignee ≡ w.id) ⇒ t1 ≡ t2

  ∀t:Task, ∀w:Worker :
    assign(t, w) ⇒ (t.priority ≥ min_unassigned_priority() ∨ ¬∃u:Task:u.status≡unassigned)

  expired(t) ≜ t.deadline ≤ now() → t.status ≔ expired ∧ t.assignee ≔ ∅
  complete(t,w) ≜ t.status≡assigned ∧ t.assignee≡w.id → t.status≔completed ∧ w.current≔∅
}

⟦Λ:Funcs⟧{
  eligible≜λ(t:Task).
    t.status ≡ unassigned ∧ t.deadline > now()

  availableWorker≜λ(w:Worker).
    w.active ≡ true ∧ w.current ≡ ∅

  nextTask≜λ(s:Schedule).
    let candidates ≔ {t ∈ s.tasks | eligible(t)} in
    let p_max      ≔ max({t.priority | t ∈ candidates}) in
    let top        ≔ {t ∈ candidates | t.priority ≡ p_max} in
    argmin(t ∈ top, t.deadline)

  assign≜λ(s:Schedule, w:Worker).
    let t ≔ nextTask(s) in
    t ≠ ∅ ∧ availableWorker(w) →
      s.assignments ∪ {Assignment{task_id≔t.id, worker_id≔w.id, assigned_at≔now()}}
      ∧ t.status     ≔ assigned
      ∧ t.assignee   ≔ w.id
      ∧ w.current    ≔ t.id
      ∧ w.capacity   ≔ 0

  scheduleAll≜λ(s:Schedule).
    let ws ≔ {w ∈ s.workers | availableWorker(w)} in
    fold(assign(s, ·), ws, s)
}

